const incoming = items[0].json || {};
const source = incoming.body && typeof incoming.body === 'object' ? incoming.body : incoming;
const item = {
  ...source,
  requested_at: source.requested_at || incoming.headers?.['x-requested-at'] || new Date().toISOString(),
  status: source.status || 'pending'
};
const company = (item.company_name || '').toString().trim();
if (!company) {
  throw new Error('company_name is required in the intake sheet.');
}
const days = Number(item.time_period_days || item.time_period || item.days || 14);
const allowed = [14, 30, 60];
const normalizedDays = allowed.includes(days) ? days : 14;
const now = new Date();
const end = now.toISOString().slice(0, 10);
const startDateObj = new Date(now);
startDateObj.setUTCDate(startDateObj.getUTCDate() - normalizedDays);
const start = startDateObj.toISOString().slice(0, 10);
const slug = company
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '_')
  .replace(/^_+|_+$/g, '')
  .slice(0, 60) || 'company';
const runId = `${slug}_${end}_${normalizedDays}d_${item.row_number || 0}`;
const secCik = (item.sec_cik || '').toString().replace(/\D/g, '');
const paddedCik = secCik ? secCik.padStart(10, '0') : '';
const shortCik = secCik ? secCik.replace(/^0+/, '') : '';
const rawDomain = (item.company_domain || item.official_domain || '').toString().trim().toLowerCase();
const companyDomain = rawDomain
  .replace(/^https?:\/\//, '')
  .replace(/^www\./, '')
  .replace(/\/.*$/, '');
const officialDomains = ['sec.gov', 'businesswire.com', 'prnewswire.com', 'globenewswire.com'];
if (companyDomain) {
  officialDomains.unshift(companyDomain);
  officialDomains.unshift(`investor.${companyDomain}`);
  officialDomains.unshift(`ir.${companyDomain}`);
  officialDomains.unshift(`investors.${companyDomain}`);
}
const dedup = (arr) => [...new Set(arr.filter(Boolean))];
const officialDomainsFinal = dedup(officialDomains);
const governmentDomains = ['lda.senate.gov', 'opensecrets.org', 'usaspending.gov', 'sam.gov', 'federalregister.gov'];
const thinktankDomains = ['csis.org', 'brookings.edu', 'rand.org', 'cfr.org', 'cnas.org', 'carnegieendowment.org', 'aei.org'];
const officialQuery = paddedCik
  ? `"${company}" ${shortCik} ("8-K" OR "10-Q" OR "10-K" OR "earnings release" OR "investor relations" OR "press release")`
  : `"${company}" ("8-K" OR "10-Q" OR "10-K" OR "earnings release" OR "investor relations" OR "press release")`;
const governmentQuery = `"${company}" ("LD-2" OR lobbying OR procurement OR "Senate lobbying" OR "Federal Register")`;
const thinktankQuery = `"${company}" (regulation OR policy OR analysis OR briefing OR strategic risk)`;
const newsQuery = `"${company}" (earnings OR acquisition OR divestiture OR lawsuit OR regulation OR contract)`;
return [{
  json: {
    ...item,
    company_name: company,
    sec_cik: paddedCik,
    sec_cik_short: shortCik,
    company_domain: companyDomain,
    time_period_days: normalizedDays,
    time_period_label: item.time_period_label || `${normalizedDays} days`,
    start_date: start,
    end_date: end,
    safe_file_name: slug,
    run_id: runId,
    official_domains: officialDomainsFinal,
    government_domains: governmentDomains,
    thinktank_domains: thinktankDomains,
    official_query: officialQuery,
    government_query: governmentQuery,
    thinktank_query: thinktankQuery,
    news_query: newsQuery,
    scraped_at: new Date().toISOString()
  }
}];

