const docs = items.map(i => i.json);
const first = docs[0] || {};

const company = (first.company_name || '').toString().trim();
const companyNorm = company.toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim();
const companyTokens = companyNorm.split(' ').filter(t => t.length > 2);
const secCik = (first.sec_cik || '').toString().replace(/\D/g, '');
const shortCik = secCik.replace(/^0+/, '');
const companyDomain = (first.company_domain || '').toString().toLowerCase().replace(/^www\./, '');
const start = new Date(`${first.start_date}T00:00:00Z`);
const end = new Date(`${first.end_date}T23:59:59Z`);
const endYear = end.getUTCFullYear();

const monthMap = {
  january: 1, jan: 1, february: 2, feb: 2, march: 3, mar: 3, april: 4, apr: 4, may: 5,
  june: 6, jun: 6, july: 7, jul: 7, august: 8, aug: 8, september: 9, sept: 9, sep: 9,
  october: 10, oct: 10, november: 11, nov: 11, december: 12, dec: 12
};

function hostname(url = '') {
  try { return new URL(url).hostname.toLowerCase().replace(/^www\./, ''); } catch (e) { return ''; }
}

function normalize(text = '') {
  return text.toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim();
}

function companyScore(doc) {
  const text = [doc.title, doc.snippet, (doc.content_excerpt || '').slice(0, 1500), doc.url].join(' ');
  const n = normalize(text);
  if (!companyNorm) return 0;
  let score = 0;
  if (n.includes(companyNorm)) score += 0.7;
  const tokenMatches = companyTokens.filter(t => n.includes(t)).length;
  if (companyTokens.length) score += Math.min(0.3, tokenMatches / companyTokens.length * 0.3);
  if ((doc.url || '').toLowerCase().includes(companyNorm.replace(/\s+/g, '-'))) score += 0.1;
  return Math.min(1, score);
}

function parseDateValue(raw) {
  if (!raw) return null;
  const value = raw.toString().trim();
  if (!value) return null;
  const direct = new Date(value);
  if (!Number.isNaN(direct.getTime())) return direct;
  const iso = value.match(/(20\d{2})-(\d{2})-(\d{2})/);
  if (iso) return new Date(`${iso[1]}-${iso[2]}-${iso[3]}T00:00:00Z`);
  const mdy = value.match(/(\d{1,2})\/(\d{1,2})\/(20\d{2})/);
  if (mdy) return new Date(`${mdy[3]}-${mdy[1].padStart(2,'0')}-${mdy[2].padStart(2,'0')}T00:00:00Z`);
  return null;
}

function parseTopTextDate(text = '') {
  const sample = text.slice(0, 2000);
  let m = sample.match(/\b(20\d{2})-(\d{2})-(\d{2})\b/);
  if (m) return { date: new Date(`${m[1]}-${m[2]}-${m[3]}T00:00:00Z`), source: 'text_iso' };
  m = sample.match(/\b(\d{1,2})\/(\d{1,2})\/(20\d{2})\b/);
  if (m) return { date: new Date(`${m[3]}-${m[1].padStart(2,'0')}-${m[2].padStart(2,'0')}T00:00:00Z`), source: 'text_mdy' };
  m = sample.match(/\b(January|Jan|February|Feb|March|Mar|April|Apr|May|June|Jun|July|Jul|August|Aug|September|Sept|Sep|October|Oct|November|Nov|December|Dec)\.?\s+(\d{1,2}),\s+(20\d{2})\b/i);
  if (m) {
    const month = monthMap[m[1].toLowerCase()];
    return { date: new Date(`${m[3]}-${String(month).padStart(2,'0')}-${String(m[2]).padStart(2,'0')}T00:00:00Z`), source: 'text_month_day_year' };
  }
  m = sample.match(/\b(\d{1,2})\s+(January|Jan|February|Feb|March|Mar|April|Apr|May|June|Jun|July|Jul|August|Aug|September|Sept|Sep|October|Oct|November|Nov|December|Dec)\s+(20\d{2})\b/i);
  if (m) {
    const month = monthMap[m[2].toLowerCase()];
    return { date: new Date(`${m[3]}-${String(month).padStart(2,'0')}-${String(m[1]).padStart(2,'0')}T00:00:00Z`), source: 'text_day_month_year' };
  }
  return null;
}

function parseUrlDate(url = '') {
  let m = url.match(/\/(20\d{2})\/(\d{1,2})\/(\d{1,2})(?:\/|$)/);
  if (m) return { date: new Date(`${m[1]}-${String(m[2]).padStart(2,'0')}-${String(m[3]).padStart(2,'0')}T00:00:00Z`), source: 'url_path' };
  m = url.match(/(20\d{2})-(\d{2})-(\d{2})/);
  if (m) return { date: new Date(`${m[1]}-${m[2]}-${m[3]}T00:00:00Z`), source: 'url_slug' };
  return null;
}

function bestDate(doc) {
  const pd = parseDateValue(doc.published_date);
  if (pd) return { date: pd, source: 'published_date' };
  const fromText = parseTopTextDate([doc.title, doc.snippet, (doc.content_excerpt || '').slice(0, 1500)].join(' '));
  if (fromText) return fromText;
  const fromUrl = parseUrlDate(doc.url || '');
  if (fromUrl) return fromUrl;
  return null;
}

function inWindow(date) {
  return date && date >= start && date <= end;
}

const accepted = [];
const rejected = [];

for (let idx = 0; idx < docs.length; idx++) {
  const doc = docs[idx];
  if (doc.placeholder) continue;
  const domain = hostname(doc.url || doc.source_domain || '');
  const score = companyScore(doc);
  const dated = bestDate(doc);
  const actualDate = dated ? dated.date.toISOString().slice(0, 10) : '';
  const reasons = [];

  if (score < 0.45) reasons.push('weak_company_match');
  if (!dated) reasons.push('missing_reliable_date');
  if (dated && !inWindow(dated.date)) reasons.push('outside_requested_window');

  if (doc.source_class === 'official') {
    if ((doc.url || '').includes('/edgar/browse/')) reasons.push('edgar_entity_landing_page');
    if (domain === 'sec.gov' && secCik) {
      const url = (doc.url || '').toLowerCase();
      if (!url.includes(`/data/${shortCik}/`) && !url.includes(`cik=${shortCik}`) && !url.includes(`cik=${secCik}`)) {
        reasons.push('sec_cik_mismatch');
      }
    }
    if (companyDomain && domain && domain !== 'sec.gov' && domain !== 'businesswire.com' && domain !== 'prnewswire.com' && domain !== 'globenewswire.com') {
      if (!(domain === companyDomain || domain.endsWith(`.${companyDomain}`))) reasons.push('non_company_official_domain');
    }
  }

  if (doc.source_class === 'government' && domain.includes('opensecrets.org')) {
    const cycleMatch = (doc.url || '').match(/[?&]cycle=(20\d{2})/);
    if (cycleMatch && Number(cycleMatch[1]) < endYear - 1) reasons.push('old_opensecrets_cycle');
  }

  const output = {
    ...doc,
    source_domain: domain || doc.source_domain || '',
    actual_doc_date: actualDate,
    date_source: dated ? dated.source : '',
    entity_confidence: Number(score.toFixed(2)),
    validation_notes: reasons.join('|'),
    validation_status: reasons.length ? 'rejected' : 'accepted',
    placeholder: false
  };

  if (reasons.length) rejected.push({ json: output, pairedItem: { item: idx } });
  else accepted.push({ json: output, pairedItem: { item: idx } });
}

if (accepted.length === 0) {
  return [{
    pairedItem: { item: 0 },
    json: {
      run_id: first.run_id || '',
      row_number: first.row_number || '',
      company_name: first.company_name || '',
      sec_cik: first.sec_cik || '',
      company_domain: first.company_domain || '',
      time_period_days: first.time_period_days || '',
      time_period_label: first.time_period_label || '',
      start_date: first.start_date || '',
      end_date: first.end_date || '',
      source_class: 'none',
      source_domain: '',
      title: 'No validated documents found within the requested window',
      url: '',
      published_date: '',
      actual_doc_date: '',
      date_source: '',
      scraped_at: new Date().toISOString(),
      query_used: '',
      snippet: '',
      content_excerpt: '',
      content_length: 0,
      source_rank: 0,
      duplicate_flag: false,
      entity_confidence: 0,
      validation_notes: rejected.length ? 'all_documents_rejected_by_validation' : 'no_documents_found',
      validation_status: 'placeholder',
      placeholder: true
    }
  }];
}

return accepted;

const target = (($('Normalize Inputs').item.json.company_name || '') + '').trim().toLowerCase();
const rows = items.map(i => i.json || {});
const match = rows.find(r => (((r.company_name || r.Company || '') + '').trim().toLowerCase() === target)) || {};
const note = {
  company_name: match.company_name || match.Company || $('Normalize Inputs').item.json.company_name || '',
  industries: match.industries || match['What industries are they in'] || '',
  operating_regions: match.operating_regions || match['Where do they operate'] || '',
  sensitivities: match.other_sensitivities || match['Other sensitivities'] || '',
  requested_briefings: match.requested_briefings || match['What have they requested briefings on'] || '',
  future_interests: match.future_interests || match['Best Guess for Future Interests'] || ''
};
const hasNote = Object.values(note).some(v => (v || '').toString().trim() !== '');
const bundle = hasNote
  ? [
      `Company: ${note.company_name}`,
      `Industries: ${note.industries}`,
      `Where they operate: ${note.operating_regions}`,
      `Other sensitivities: ${note.sensitivities}`,
      `Requested briefings: ${note.requested_briefings}`,
      `Best guess for future interests: ${note.future_interests}`
    ].join('\n')
  : 'No past CSIS engagement memo found for this company.';
return [{
  json: {
    company_note_found: hasNote,
    company_note_struct: note,
    company_note_bundle: bundle
  },
  pairedItem: { item: 0 }
}];

const rows = items.map(i => i.json || {}).filter(r => (r.expert_name || r['Expert Name'] || '').toString().trim());
const fmt = (r, idx) => {
  const name = r.expert_name || r['Expert Name'] || '';
  const bio = (r.bio || r.Bio || '').toString().slice(0, 1200);
  const prev = (r.previous_experience || r['Previous Experience'] || '').toString().slice(0, 800);
  const topics = (r.topics || r.Topics || '').toString();
  return [
    `Expert ${idx + 1}`,
    `Name: ${name}`,
    `Topics: ${topics}`,
    `Bio: ${bio}`,
    `Previous experience: ${prev}`
  ].join('\n');
};
const bundle = rows.map(fmt).join('\n\n---\n\n');
return [{
  json: {
    csis_experts_count: rows.length,
    csis_experts_bundle: bundle || 'No CSIS experts rows were found.'
  },
  pairedItem: { item: 0 }
}];

